class CryptoWallet {
    var privateKey: Data?
    var publicKey: Data?

    func generateKeyPair() -> (Data, Data) {
        let keyPair = ECParameterCurves.P521.generateKeyPair()
        self.privateKey = keyPair.privateKey.rawRepresentation
        self.publicKey = keyPair.publicKey.rawRepresentation
        return (self.privateKey!, self.publicKey!)
    }

    func signTransaction(transaction: Data) -> Data? {
        guard let privateKey = self.privateKey else { return nil }
        let signature = ECDSA.sign(privateKey: privateKey, message: transaction)
        return signature
    }

    func verifyTransaction(transaction: Data, signature: Data?) -> Bool {
        guard let publicKey = self.publicKey else { return false }
        return ECDSA.verify(publicKey: publicKey, message: transaction, signature: signature!)
    }
}

